import { products } from "../../data/products";

export default function FeaturedStrip({ setPage }) {
  const featured = products.slice(0, 3);

  return (
    <section className="featured-strip">
      <div className="strip-header">
        <h2>Featured</h2>
        <button className="link-btn" onClick={() => setPage("shop")}>
          View all →
        </button>
      </div>
      <div className="strip-grid">
        {featured.map((product) => (
          <div key={product.id} className="strip-card" style={{ "--card-accent": product.color }}>
            <div className="strip-img" style={{ background: product.color }}>
              <img className="product-image" src={product.image} alt={product.name} />
            </div>
            <div className="strip-info">
              <span className="strip-cat">{product.category}</span>
              <span className="strip-name">{product.name}</span>
              <span className="strip-price">₹{product.price.toLocaleString()}</span>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
}
